// Generic task library for unmapped roles — generated from score context
function buildGenericTasks(score: number): RoleTask[] {
  const isHighRisk = score >= 65;
  return [
    { id: 'g1', name: 'Routine data processing and reporting',    category: 'vulnerable',    automationRisk2026: isHighRisk ? 80 : 55, automationRisk2030: isHighRisk ? 93 : 72, humanAdvantageScore: isHighRisk ? 10 : 30, aiToolsAffecting: ['AI copilots','Automation tools'] },
    { id: 'g2', name: 'Template-based document creation',         category: 'vulnerable',    automationRisk2026: isHighRisk ? 75 : 50, automationRisk2030: isHighRisk ? 90 : 70, humanAdvantageScore: isHighRisk ? 12 : 32, aiToolsAffecting: ['Copilot','ChatGPT'] },
    { id: 'g3', name: 'Complex stakeholder decision-making',      category: 'high-value',    automationRisk2026: 15, automationRisk2030: 30, humanAdvantageScore: 85, aiToolsAffecting: [], whyProtected: 'Requires organizational context, trust, and human accountability' },
    { id: 'g4', name: 'Domain expertise and specialist judgment', category: 'high-value',    automationRisk2026: 20, automationRisk2030: 38, humanAdvantageScore: 80, aiToolsAffecting: [], whyProtected: 'Contextual expertise built over years cannot be fully encoded in AI training data' },
    { id: 'g5', name: 'Team leadership and people management',    category: 'high-value',    automationRisk2026: 12, automationRisk2030: 25, humanAdvantageScore: 88, aiToolsAffecting: [], whyProtected: 'Human relationships and trust are the core product of management' },
    { id: 'g6', name: 'Standard procedural task execution',       category: 'fast-changing', automationRisk2026: isHighRisk ? 82 : 60, automationRisk2030: isHighRisk ? 94 : 80, humanAdvantageScore: isHighRisk ? 8 : 28, aiToolsAffecting: ['Automation platforms'] },
    { id: 'g7', name: 'Creative problem-solving in novel contexts', category: 'protected',   automationRisk2026: 28, automationRisk2030: 50, humanAdvantageScore: 68, aiToolsAffecting: [], whyProtected: 'Novel situations without prior training data require genuine human reasoning' },
  ];
}

export function getRoleTasks(roleKey: string, score = 50): RoleTask[] {
  return TASKS[roleKey] ?? buildGenericTasks(score);
}

export function getTaskSpotlights(tasks: RoleTask[]): {
  mostVulnerable: RoleTask;
  mostProtected: RoleTask;
  fastestChanging: RoleTask;
  highestValue: RoleTask;
} {
  const sorted = [...tasks];

  const mostVulnerable   = sorted.sort((a, b) => b.automationRisk2026 - a.automationRisk2026)[0];
  const mostProtected    = sorted.sort((a, b) => b.humanAdvantageScore - a.humanAdvantageScore)[0];
  const fastestChanging  = tasks
    .filter(t => t.category === 'fast-changing')
    .sort((a, b) => (b.automationRisk2030 - b.automationRisk2026) - (a.automationRisk2030 - a.automationRisk2026))[0]
    ?? tasks.sort((a, b) => (b.automationRisk2030 - b.automationRisk2026) - (a.automationRisk2030 - a.automationRisk2026))[0];
  const highestValue     = tasks
    .filter(t => t.category === 'high-value')
    .sort((a, b) => b.humanAdvantageScore - a.humanAdvantageScore)[0]
    ?? mostProtected;

  return { mostVulnerable, mostProtected, fastestChanging, highestValue };
}

export function getTaskCounts(tasks: RoleTask[]): Record<string, number> {
  const counts: Record<string, number> = { vulnerable: 0, protected: 0, 'fast-changing': 0, 'high-value': 0 };
  for (const t of tasks) counts[t.category] = (counts[t.category] ?? 0) + 1;
  return counts;
}
